import {
  defineUpdate,
  defineSignal,
  setHandler,
  condition,
} from '@temporalio/workflow';
import { ApplicationFailure } from '@temporalio/common';

export const depositUpdate = defineUpdate<number, [number]>('deposit');
export const finishSignal = defineSignal('finish');

export async function BankBalanceWorkflow(): Promise<number> {
  let balance = 0;
  let isFinished = false;

  setHandler(
    depositUpdate,
    (amount: number) => {
      balance += amount;
      return balance;
    },
    {
      validator: (amount: number) => {
        if (amount <= 0) {
          throw ApplicationFailure.create({
            message: 'Amount must be positive',
            type: 'InvalidAmount',
          });
        }
      },
    }
  );

  setHandler(finishSignal, () => {
    isFinished = true;
  });

  await condition(() => isFinished);

  return balance;
}

import { Worker, NativeConnection } from '@temporalio/worker';
import * as workflows from './workflows';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const apiKey = process.env.TEMPORAL_API_KEY;

  if (!address || !namespace || !apiKey) {
    throw new Error('Missing Temporal Cloud credentials in environment variables');
  }

  const connection = await NativeConnection.connect({
    address,
    tls: {
      apiKey,
    },
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'update-handler-ts',
    workflowsPath: require.resolve('./workflows'),
  });

  console.log('Worker started');
  await worker.run();
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

import { Connection, Client } from '@temporalio/client';
import { BankBalanceWorkflow, depositUpdate, finishSignal } from './workflows';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address || !namespace || !apiKey || !runId) {
    throw new Error('Missing environment variables');
  }

  const connection = await Connection.connect({
    address,
    tls: {
      apiKey,
    },
  });

  const client = new Client({
    connection,
    namespace,
  });

  const workflowId = `update-wf-${runId}`;

  const handle = await client.workflow.start(BankBalanceWorkflow, {
    taskQueue: 'update-handler-ts',
    workflowId,
  });

  const amounts = [100, 50, 25];
  for (const amount of amounts) {
    const balance = await handle.executeUpdate(depositUpdate, {
      args: [amount],
    });
    console.log(`Updated balance: ${balance}`);
  }

  await handle.signal(finishSignal);
  const result = await handle.result();
  console.log(`Final balance: ${result}`);
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

